/* Element selector: targets ALL <p> elements */
p {
  font-size: 16px;
  line-height: 1.6;
}

/* Class selector: targets elements with class="highlight" */
.highlight {
  background-color: #fef3c7;
  padding: 2px 6px;
  border-radius: 3px;
}

/* ID selector: targets the ONE element with id="nav" */
#nav {
  background-color: #1e293b;
  padding: 12px 24px;
}

/* Multiple classes on one element */
.btn {
  padding: 8px 16px;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}

.btn-primary {
  background-color: #2563eb;
  color: white;
}

.btn-danger {
  background-color: #dc2626;
  color: white;
}

/* Universal selector: matches EVERY element */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

/* Grouping: same styles for multiple selectors */
h1,
h2,
h3,
h4 {
  font-family: Georgia, serif;
  color: #1f2937;
  margin-bottom: 12px;
}

/* Mix different selector types in a group */
.subtitle,
.caption,
small {
  font-size: 14px;
  color: #6b7280;
}

/* Without grouping, you would need to repeat: */
/*
h1 { font-family: Georgia, serif; color: #1f2937; margin-bottom: 12px; }
h2 { font-family: Georgia, serif; color: #1f2937; margin-bottom: 12px; }
h3 { font-family: Georgia, serif; color: #1f2937; margin-bottom: 12px; }
*/

/* Has attribute */
[title] {
  cursor: help;
  border-bottom: 1px dotted #999;
}

/* Exact value match */
input[type="email"] {
  border: 2px solid #3b82f6;
}

input[type="password"] {
  border: 2px solid #8b5cf6;
}

/* Starts with (^=) */
a[href^="https"] {
  color: green;
}

/* Ends with ($=) */
a[href$=".pdf"] {
  color: #dc2626;
}

/* Contains (*=) */
[class*="col-"] {
  float: left;
  padding: 0 15px;
}

