exercises.solution:
.container p { color: blue; }  /* Specificity: 0,0,1,1 */
p.intro { color: red; }        /* Specificity: 0,0,1,1 */
p { color: gray; }             /* Specificity: 0,0,0,1 */

/* For a <div class="container"><p class="intro">Text</p></div> */
/* Answer: RED. Both .container p and p.intro have specificity 0,0,1,1 */
/* but p.intro comes later in source order, so it wins. */

/* Make the text green without !important: */
.container p.intro { color: green; }  /* Specificity: 0,0,2,1 - wins */

